                            >
                                <span className="material-icons mr-2">groups</span>
                                {t('team.hero.meetTeam') || 'Explore Our Faculty'}
                            </a>
                            <a 
                                href="/contact" 
                                className="inline-flex items-center px-8 py-4 border-2 border-gray-800 text-gray-800 font-semibold text-lg rounded-full hover:bg-gray-800 hover:text-white transition-all duration-300 hover:shadow-lg transform hover:scale-105"
                            >
                                <span className="material-icons mr-2">work</span>
                                {t('team.hero.joinUs') || 'Join Our Team'}
                            </a>
                        </div>
                    </div>
                </div>

                <div className="scroll-indicator">
                    <a href="#team-members">
                        <span>{t('team.hero.exploreTeam') || 'Explore Our Team'}</span>
                        <span className="material-icons">keyboard_arrow_down</span>
                    </a>
                </div>
            </section>

            {/* Team Section */}
            <section id="team-members" className="about-section py-20 bg-gradient-to-br from-gray-50 to-blue-50">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                    {/* Section Header */}
                    <div className="text-center mb-16">
                        <h2 className="text-4xl font-bold text-gray-900 mb-4">
                            Meet Our <span className="text-blue-600">Amazing Team</span>
                        </h2>
                        <p className="text-lg text-gray-600 max-w-3xl mx-auto">
                            Our dedicated team of professionals brings years of industry experience and passion for education to help you succeed in your learning journey.
                        </p>
                    </div>

                    {/* Tab Navigation */}
                    <div className="flex justify-center mb-12">
                        <div className="bg-white rounded-2xl p-2 shadow-lg border border-gray-200">
                            <div className="flex space-x-2">
                                {tabs.map((tab) => {
                                    const IconComponent = tab.icon;
                                    return (
                                        <button
                                            key={tab.id}
                                            onClick={() => setActiveTab(tab.id)}
                                            className={`flex items-center space-x-2 px-6 py-3 rounded-xl font-medium transition-all duration-300 ${
                                                activeTab === tab.id
                                                    ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg transform scale-105'
                                                    : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50'
                                            }`}
                                        >
                                            <IconComponent className="w-5 h-5" />
                                            <span>{tab.label}</span>
                                        </button>
                                    );
                                })}
                            </div>
                        </div>
                    </div>

                    {/* Team Grid */}
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
                        {(() => {
                            switch(activeTab) {
                                case 'teachers':
                                    return teachersData.map((member) => (
                                        <TeamCard key={member.id} member={member} />
                                    ));
                                case 'management':
                                    return managementData.map((member) => (
                                        <TeamCard key={member.id} member={member} />
                                    ));
                                case 'career':
                                    return careerData.map((member) => (
                                        <TeamCard key={member.id} member={member} />
                                    ));
                                case 'admin':
                                    return adminOfficeData.map((member) => (
                                        <TeamCard key={member.id} member={member} />
                                    ));
                                case 'tech':
                                    return techSupportData.map((member) => (
                                        <TeamCard key={member.id} member={member} />
                                    ));
                                default:
                                    return teachersData.map((member) => (
                                        <TeamCard key={member.id} member={member} />
                                    ));
                                }
                        })()}
                    </div>
                </div>
            </section>
        </div>
    );
};

export default Team;
